  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '用例名称',
  `description` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '用例描述',
  `suite_id` bigint NOT NULL COMMENT '所属用例集ID',
  `script` json NULL COMMENT '步骤列表',
  `status` int NULL DEFAULT 0 COMMENT '状态：0=未执行，1=通过，2=失败',
  `creation_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `created_by` bigint NULL DEFAULT NULL,
  `updation_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `updated_by` bigint NULL DEFAULT NULL,
  `enabled_flag` tinyint(1) NOT NULL DEFAULT 1,
  `trace_id` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `case_type` int NOT NULL DEFAULT 1 COMMENT '用例类型：1=正向，2=负向，3=边界值，4=安全性，5=其他',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = Dynamic;

