INSERT INTO `sys_message` VALUES (134, 41, 'assistant', '我的知识库包含了大量的信息，这些信息主要来自于我被训练时所使用的数据集。这包括但不限于：\n\n- 世界历史、文化、地理等人文社科知识\n- 数学、物理、化学、生物等自然科学知识\n- 医学、健康和医疗保健知识\n- 技术和计算机科学知识\n- 语言和文学知识\n- 经济、商业和金融知识\n- 法律知识\n- 环境科学知识\n- 体育和娱乐知识\n\n需要注意的是，我的知识截止日期是2024年10月，之后发生的事件或新出现的信息可能不会在我的知识库中。此外，我无法访问实时数据或个人账户信息，也不包含任何非法或成人内容。如果您有具体问题，我会尽力根据我的知识库为您提供帮助。', 'text', 'null', 277, '2026-04-07 16:04:52', 1, '2026-04-07 16:04:52', 1, 1, NULL);
