INSERT INTO `ui_test_cases` VALUES (54, 1, '验证勾选“记住密码”后7天内免密登录', 'LOGIN_015', 'medium', NULL, '用户已注册', '用户名和密码自动填充，可直接登录', '2026-02-26 10:12:27', 1, '2026-02-26 10:12:27', NULL, 1, NULL);
