INSERT INTO `ui_test_cases` VALUES (57, 1, '验证第1次登录失败不触发锁定', 'LOGIN_018', 'high', NULL, '用户已注册', '显示“用户名或密码错误”，账号未锁定', '2026-02-26 10:12:27', 1, '2026-02-26 10:12:27', NULL, 1, NULL);
