INSERT INTO `ui_test_cases` VALUES (59, 1, '验证第3次连续登录失败后账号锁定', 'LOGIN_020', 'high', NULL, '用户已注册', '第三次失败后提示“账号已锁定，请30分钟后重试”，登录按钮前端禁用且后端拒绝请求', '2026-02-26 10:12:27', 1, '2026-02-26 10:12:27', NULL, 1, NULL);
